Sure! Here's a basic UserProfile component using functional React with TypeScript:

```tsx
interface UserProfileProps {
  name: string;
  avatarUrl: string;
  bio: string;
}

export function UserProfile({ name, avatarUrl, bio }: UserProfileProps) {
  return (
    <div className="profile-card">
      <img src={avatarUrl} alt={`${name}'s avatar`} className="avatar" />
      <h2>{name}</h2>
      <p>{bio}</p>
    </div>
  );
}
```
